// Map fields for app.js compatibility (site is Kazakh-only)
CURRICULUM.modules.forEach(mod => {
  mod.title = mod.name_kz;
  mod.subtitle = '';
  if (mod.topics) {
    mod.topics.forEach(topic => {
      topic.title = topic.name_kz;
      // Flatten theory to HTML string (prefer kz, fallback ru)
      if (topic.theory && typeof topic.theory === 'object') {
        topic.theory = topic.theory.kz || topic.theory.ru || '';
      }
      // Map practiceQuestions -> practice, quizQuestions -> quiz
      if (topic.practiceQuestions) {
        topic.practice = topic.practiceQuestions;
      }
      if (topic.quizQuestions) {
        topic.quiz = topic.quizQuestions;
      }
    });
  }
});

// App.js expects CURRICULUM.grade5 as flat array of all modules
CURRICULUM.grade5 = CURRICULUM.modules;
CURRICULUM.allModules = CURRICULUM.modules;

// Helper functions used by app.js
function getModuleById(id) {
  return CURRICULUM.modules.find(m => m.id === id);
}

function getTopicById(moduleId, topicId) {
  const mod = getModuleById(moduleId);
  if (!mod || !mod.topics) return null;
  return mod.topics.find(t => t.id === topicId);
}

function getModulesByGrade(grade) {
  const g = parseInt(grade);
  return CURRICULUM.modules.filter(m => m.grade === g);
}

// Export for browser
if (typeof window !== 'undefined') {
  window.CURRICULUM = CURRICULUM;
  window.getModuleById = getModuleById;
  window.getTopicById = getTopicById;
  window.getModulesByGrade = getModulesByGrade;
}
